const token = process.env.SUPERVISOR_TOKEN || "";
if (!token) {
    node.error("SUPERVISOR_TOKEN introuvable");
    return null;
}

msg.method = "GET";
msg.url = "http://supervisor/core/api/states";
msg.headers = {
    Authorization: `Bearer ${token}`,
    "Content-Type": "application/json"
};
return msg;

const cfg = msg.cfg;
const list = Array.isArray(msg.payload) ? msg.payload : [];

const states = {};
for (const item of list) {
    if (item && item.entity_id) {
        states[item.entity_id] = item;
    }
}

function num(entityId) {
    if (!entityId || !states[entityId]) return 0;
    const n = Number(states[entityId].state);
    return Number.isFinite(n) ? n : 0;
}

function str(entityId) {
    if (!entityId || !states[entityId]) return "";
    return String(states[entityId].state || "").trim();
}

msg.inputs = {
    solarDay: cfg.solarEnabled && cfg.solarInputMode === "energy" ? num(cfg.solarEnergyEntity) : 0,
    loadDay: cfg.loadEnabled && cfg.loadInputMode === "energy" ? num(cfg.loadEnergyEntity) : 0,
    gridImportDay: cfg.gridEnabled && cfg.gridInputMode === "energy" ? num(cfg.gridImportEnergyEntity) : 0,
    gridExportDay: cfg.gridEnabled && cfg.gridInputMode === "energy" ? num(cfg.gridExportEnergyEntity) : 0,
    batteryChargeDay: cfg.batteryEnabled && cfg.batteryInputMode === "energy" ? num(cfg.batteryChargeEnergyEntity) : 0,
    batteryDischargeDay: cfg.batteryEnabled && cfg.batteryInputMode === "energy" ? num(cfg.batteryDischargeEnergyEntity) : 0,

    solarPower: cfg.solarEnabled && cfg.solarInputMode === "power" ? num(cfg.solarPowerEntity) : 0,
    loadPower: cfg.loadEnabled && cfg.loadInputMode === "power" ? num(cfg.loadPowerEntity) : 0,
    gridImportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridImportPowerEntity) : 0,
    gridExportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridExportPowerEntity) : 0,
    batteryChargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryChargePowerEntity) : 0,
    batteryDischargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryDischargePowerEntity) : 0,

    tempoColorRaw: cfg.contractType === "tempo" ? str(cfg.tempo.colorEntity) : ""
};

return msg;

const cfg = msg.cfg;
const inputs = msg.inputs || {};

function round(v, d = 4) {
    return Number((Number(v || 0)).toFixed(d));
}

function hhmmToMinutes(s) {
    if (!s || !/^\d{2}:\d{2}$/.test(s)) return null;
    const [h, m] = s.split(":").map(Number);
    if (!Number.isInteger(h) || !Number.isInteger(m)) return null;
    if (h < 0 || h > 23 || m < 0 || m > 59) return null;
    return h * 60 + m;
}

function minuteOfDay(t) {
    return (Number(t.hour) * 60) + Number(t.minute);
}

function isMinuteInRange(minute, start, end) {
    const s = hhmmToMinutes(start);
    const e = hhmmToMinutes(end);
    if (s === null || e === null) return false;
    if (s === e) return true;
    if (s < e) return minute >= s && minute < e;
    return minute >= s || minute < e;
}

function normalizeTempoColor(v) {
    const s = String(v || "").trim().toLowerCase();
    if (s === "bleu") return "blue";
    if (s === "blanc") return "white";
    if (s === "rouge") return "red";
    if (s === "inconnu") return "unknown";
    return "unknown";
}

function isTempoHc(minute, tempoCfg) {
    return (
        isMinuteInRange(minute, tempoCfg.hcSlot1Start, tempoCfg.hcSlot1End) ||
        (tempoCfg.hcSlot2Start && tempoCfg.hcSlot2End && isMinuteInRange(minute, tempoCfg.hcSlot2Start, tempoCfg.hcSlot2End)) ||
        (tempoCfg.hcSlot3Start && tempoCfg.hcSlot3End && isMinuteInRange(minute, tempoCfg.hcSlot3Start, tempoCfg.hcSlot3End))
    );
}

function dateParts(tz) {
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false
    }).formatToParts(new Date());

    const m = {};
    for (const p of parts) {
        if (p.type !== "literal") m[p.type] = p.value;
    }

    return {
        year: m.year,
        month: m.month,
        day: m.day,
        hour: m.hour,
        minute: m.minute,
        second: m.second,
        dayKey: `${m.year}-${m.month}-${m.day}`,
        monthKey: `${m.year}-${m.month}`,
        yearKey: `${m.year}`
    };
}

function emptyEnergy() {
    return {
        solar: 0,
        load: 0,
        gridImport: 0,
        gridExport: 0,
        batteryCharge: 0,
        batteryDischarge: 0
    };
}

function currentDaySnapshot(inputs) {
    return {
        solar: Number(inputs.solarDay || 0),
        load: Number(inputs.loadDay || 0),
        gridImport: Number(inputs.gridImportDay || 0),
        gridExport: Number(inputs.gridExportDay || 0),
        batteryCharge: Number(inputs.batteryChargeDay || 0),
        batteryDischarge: Number(inputs.batteryDischargeDay || 0)
    };
}

function addEnergy(a, b) {
    return {
        solar: round(Number(a.solar || 0) + Number(b.solar || 0), 6),
        load: round(Number(a.load || 0) + Number(b.load || 0), 6),
        gridImport: round(Number(a.gridImport || 0) + Number(b.gridImport || 0), 6),
        gridExport: round(Number(a.gridExport || 0) + Number(b.gridExport || 0), 6),
        batteryCharge: round(Number(a.batteryCharge || 0) + Number(b.batteryCharge || 0), 6),
        batteryDischarge: round(Number(a.batteryDischarge || 0) + Number(b.batteryDischarge || 0), 6)
    };
}

function proratedSubscription(periodName, monthlyPrice, time) {
    const p = Number(monthlyPrice || 0);
    if (!p) return 0;
    if (periodName === "day") {
        const daysInMonth = new Date(Number(time.year), Number(time.month), 0).getDate();
        return p / daysInMonth;
    }
    if (periodName === "month") return p;
    if (periodName === "year") return p * 12;
    return 0;
}

const now = dateParts(cfg.tz || "UTC");

let store = flow.get("finance_store", "persistent") || {
    keys: {
        dayKey: now.dayKey,
        monthKey: now.monthKey,
        yearKey: now.yearKey
    },
    closedDayMonthAccumulator: emptyEnergy(),
    closedDayYearAccumulator: emptyEnergy(),
    currentDaySnapshot: emptyEnergy(),
    lastClosedDayKey: "",
    meta: {
        lastTempoColor: "",
        lastTariffName: "",
        lastTariffPeriod: "",
        lastRun: ""
    }
};

const liveDay = currentDaySnapshot(inputs);

const oldDayKey = store.keys.dayKey;
const oldMonthKey = store.keys.monthKey;
const oldYearKey = store.keys.yearKey;

if (oldDayKey !== now.dayKey) {
    if (store.lastClosedDayKey !== oldDayKey) {
        store.closedDayMonthAccumulator = addEnergy(store.closedDayMonthAccumulator, store.currentDaySnapshot);
        store.closedDayYearAccumulator = addEnergy(store.closedDayYearAccumulator, store.currentDaySnapshot);
        store.lastClosedDayKey = oldDayKey;
    }

    if (oldMonthKey !== now.monthKey) {
        store.closedDayMonthAccumulator = emptyEnergy();
    }

    if (oldYearKey !== now.yearKey) {
        store.closedDayYearAccumulator = emptyEnergy();
    }
}

store.keys = {
    dayKey: now.dayKey,
    monthKey: now.monthKey,
    yearKey: now.yearKey
};

store.currentDaySnapshot = liveDay;
store.meta.lastRun = new Date().toISOString();

function getCurrentTariff() {
    const minute = minuteOfDay(now);

    if (cfg.contractType === "fixed") {
        return {
            mode: "fixed",
            name: "fixed",
            period: "fixed",
            importPrice: Number(cfg.fixedImportPrice || 0),
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: "",
            tempoColorRaw: "",
            isTempoHc: false
        };
    }

    if (cfg.contractType === "time_based") {
        const tariffs = [cfg.tariff1, cfg.tariff2, cfg.tariff3, cfg.tariff4].filter(t => t && t.name && t.start && t.end);
        for (const t of tariffs) {
            if (isMinuteInRange(minute, t.start, t.end)) {
                return {
                    mode: "time_based",
                    name: t.name,
                    period: t.name,
                    importPrice: Number(t.price || 0),
                    exportPrice: Number(cfg.fixedExportPrice || 0),
                    tempoColor: "",
                    tempoColorRaw: "",
                    isTempoHc: false
                };
            }
        }

        return {
            mode: "time_based",
            name: "unmatched",
            period: "unmatched",
            importPrice: 0,
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: "",
            tempoColorRaw: "",
            isTempoHc: false
        };
    }

    if (cfg.contractType === "tempo") {
        const colorRaw = String(inputs.tempoColorRaw || "").trim();
        const color = normalizeTempoColor(colorRaw);
        const hc = isTempoHc(minute, cfg.tempo);

        let importPrice = 0;
        let name = "tempo_unknown";
        const period = hc ? "hc" : "hp";

        if (color === "blue") {
            importPrice = hc ? Number(cfg.tempo.blueHc || 0) : Number(cfg.tempo.blueHp || 0);
            name = hc ? "tempo_blue_hc" : "tempo_blue_hp";
        } else if (color === "white") {
            importPrice = hc ? Number(cfg.tempo.whiteHc || 0) : Number(cfg.tempo.whiteHp || 0);
            name = hc ? "tempo_white_hc" : "tempo_white_hp";
        } else if (color === "red") {
            importPrice = hc ? Number(cfg.tempo.redHc || 0) : Number(cfg.tempo.redHp || 0);
            name = hc ? "tempo_red_hc" : "tempo_red_hp";
        }

        return {
            mode: "tempo",
            name,
            period,
            importPrice,
            exportPrice: Number(cfg.fixedExportPrice || 0),
            tempoColor: color,
            tempoColorRaw: colorRaw || "inconnu",
            isTempoHc: hc
        };
    }

    return {
        mode: "fixed",
        name: "fixed",
        period: "fixed",
        importPrice: Number(cfg.fixedImportPrice || 0),
        exportPrice: Number(cfg.fixedExportPrice || 0),
        tempoColor: "",
        tempoColorRaw: "",
        isTempoHc: false
    };
}

const tariff = getCurrentTariff();

function buildPeriodFinance(acc, periodName) {
    const importEnergy = Number(acc.gridImport || 0);
    const exportEnergy = Number(acc.gridExport || 0);
    const loadEnergy = Number(acc.load || 0);
    const solarEnergy = Number(acc.solar || 0);
    const batteryCharge = Number(acc.batteryCharge || 0);
    const batteryDischarge = Number(acc.batteryDischarge || 0);

    const importCost = importEnergy * Number(tariff.importPrice || 0);
    const exportRevenue = exportEnergy * Number(tariff.exportPrice || 0);
    const theoreticalNoSolarCost = loadEnergy * Number(tariff.importPrice || 0);
    const subscriptionCost = proratedSubscription(periodName, cfg.monthlySubscriptionPrice, now);
    const realTotalWithSubscription = importCost + subscriptionCost - exportRevenue;
    const savingsVsNoSolar = theoreticalNoSolarCost - importCost + exportRevenue;

    let selfSufficiencyPct = 0;
    if (loadEnergy > 0) {
        selfSufficiencyPct = ((Math.max(0, loadEnergy - importEnergy)) / loadEnergy) * 100;
    }

    let gridDependencyPct = 0;
    if (loadEnergy > 0) {
        gridDependencyPct = (importEnergy / loadEnergy) * 100;
    }

    return {
        energy: {
            solar_kwh: round(solarEnergy),
            load_kwh: round(loadEnergy),
            grid_import_kwh: round(importEnergy),
            grid_export_kwh: round(exportEnergy),
            battery_charge_kwh: round(batteryCharge),
            battery_discharge_kwh: round(batteryDischarge)
        },
        finance: {
            import_cost: round(importCost),
            export_revenue: round(exportRevenue),
            subscription_cost: round(subscriptionCost),
            theoretical_no_solar_cost: round(theoreticalNoSolarCost),
            real_total_with_subscription: round(realTotalWithSubscription),
            savings_vs_no_solar: round(savingsVsNoSolar)
        },
        ratios: {
            self_sufficiency_pct: round(selfSufficiencyPct, 2),
            grid_dependency_pct: round(gridDependencyPct, 2)
        }
    };
}

const dayEnergy = liveDay;
const monthEnergy = addEnergy(store.closedDayMonthAccumulator, liveDay);
const yearEnergy = addEnergy(store.closedDayYearAccumulator, liveDay);

store.meta.lastTempoColor = tariff.tempoColor;
store.meta.lastTariffName = tariff.name;
store.meta.lastTariffPeriod = tariff.period;
flow.set("finance_store", store, "persistent");

if (cfg.contractType === "tempo") {
    node.status({
        fill: tariff.tempoColor === "unknown" ? "grey" : "green",
        shape: "dot",
        text: `tempo ${tariff.tempoColorRaw || "inconnu"} / ${tariff.period}`
    });
} else {
    node.status({
        fill: "blue",
        shape: "dot",
        text: `${cfg.contractType} / ${tariff.name}`
    });
}

msg.payload = {
    info: {
        module: "smart_energy_finance",
        version: "0.1.0",
        currency: cfg.currency,
        timezone: cfg.tz,
        contract_type: cfg.contractType,
        active_tariff_name: tariff.name,
        active_tariff_period: tariff.period,
        active_import_price: round(tariff.importPrice, 6),
        active_export_price: round(tariff.exportPrice, 6),
        tempo_color: tariff.tempoColor,
        tempo_color_raw: tariff.tempoColorRaw || "inconnu",
        tempo_is_hc: tariff.isTempoHc,
        day_key: now.dayKey,
        month_key: now.monthKey,
        year_key: now.yearKey,
        updated_at: new Date().toISOString()
    },
    current_inputs: {
        solar_day_kwh: inputs.solarDay,
        load_day_kwh: inputs.loadDay,
        grid_import_day_kwh: inputs.gridImportDay,
        grid_export_day_kwh: inputs.gridExportDay,
        battery_charge_day_kwh: inputs.batteryChargeDay,
        battery_discharge_day_kwh: inputs.batteryDischargeDay,
        solar_power_w: inputs.solarPower,
        load_power_w: inputs.loadPower,
        grid_import_power_w: inputs.gridImportPower,
        grid_export_power_w: inputs.gridExportPower,
        battery_charge_power_w: inputs.batteryChargePower,
        battery_discharge_power_w: inputs.batteryDischargePower
    },
    day: buildPeriodFinance(dayEnergy, "day"),
    month: buildPeriodFinance(monthEnergy, "month"),
    year: buildPeriodFinance(yearEnergy, "year")
};

return msg;

const prefix = String(env.get('MQTT_PREFIX') || 'smart_energy_finance').trim() || 'smart_energy_finance';
const currency = String(env.get('CURRENCY') || 'EUR').trim() || 'EUR';
const stateTopic = `${prefix}/state`;
const availabilityTopic = `${prefix}/availability`;
const device = {
  identifiers:['smart_energy_finance'],
  name:'Smart Energy Finance',
  manufacturer:'OpenAI User Project',
  model:'Node-RED Energy Finance Engine',
  sw_version:'0.1.0'
};

const sensors = [
  ['sef_day_import_cost','SEF Day Import Cost','{{ value_json.day.finance.import_cost }}',currency,'mdi:cash'],
  ['sef_day_export_revenue','SEF Day Export Revenue','{{ value_json.day.finance.export_revenue }}',currency,'mdi:cash-plus'],
  ['sef_day_subscription_cost','SEF Day Subscription Cost','{{ value_json.day.finance.subscription_cost }}',currency,'mdi:calendar-month'],
  ['sef_day_theoretical_no_solar_cost','SEF Day Theoretical No Solar Cost','{{ value_json.day.finance.theoretical_no_solar_cost }}',currency,'mdi:cash-remove'],
  ['sef_day_real_total_with_subscription','SEF Day Real Total With Subscription','{{ value_json.day.finance.real_total_with_subscription }}',currency,'mdi:receipt'],
  ['sef_day_savings_vs_no_solar','SEF Day Savings Vs No Solar','{{ value_json.day.finance.savings_vs_no_solar }}',currency,'mdi:cash-check'],
  ['sef_month_savings_vs_no_solar','SEF Month Savings Vs No Solar','{{ value_json.month.finance.savings_vs_no_solar }}',currency,'mdi:cash-check'],
  ['sef_year_savings_vs_no_solar','SEF Year Savings Vs No Solar','{{ value_json.year.finance.savings_vs_no_solar }}',currency,'mdi:cash-check'],
  ['sef_day_grid_import_kwh','SEF Day Grid Import','{{ value_json.day.energy.grid_import_kwh }}','kWh','mdi:transmission-tower-import'],
  ['sef_day_grid_export_kwh','SEF Day Grid Export','{{ value_json.day.energy.grid_export_kwh }}','kWh','mdi:transmission-tower-export'],
  ['sef_day_solar_kwh','SEF Day Solar','{{ value_json.day.energy.solar_kwh }}','kWh','mdi:solar-power'],
  ['sef_day_load_kwh','SEF Day Load','{{ value_json.day.energy.load_kwh }}','kWh','mdi:home-lightning-bolt'],
  ['sef_day_self_sufficiency_pct','SEF Day Self Sufficiency','{{ value_json.day.ratios.self_sufficiency_pct }}','%','mdi:percent'],
  ['sef_day_grid_dependency_pct','SEF Day Grid Dependency','{{ value_json.day.ratios.grid_dependency_pct }}','%','mdi:percent-box'],
  ['sef_active_tariff_name','SEF Active Tariff Name','{{ value_json.info.active_tariff_name }}','','mdi:label'],
  ['sef_active_import_price','SEF Active Import Price','{{ value_json.info.active_import_price }}',currency,'mdi:cash-clock'],
  ['sef_tempo_color','SEF Tempo Color','{{ value_json.info.tempo_color_raw }}','','mdi:palette']
];

const msgs = [];
for (const s of sensors) {
  const payload = {
    name: s[1],
    unique_id: s[0],
    state_topic: stateTopic,
    availability_topic: availabilityTopic,
    payload_available: 'online',
    payload_not_available: 'offline',
    value_template: s[2],
    device,
    icon: s[4]
  };
  if (s[3]) payload.unit_of_measurement = s[3];
  msgs.push({ topic:`homeassistant/sensor/${s[0]}/config`, payload:JSON.stringify(payload), retain:true });
}
msgs.push({ topic: availabilityTopic, payload:'online', retain:true });
msg.payload = msgs;
return msg;

if (msg.payload && typeof msg.payload === 'object' && msg.payload.topic) return msg.payload;
if (Array.isArray(msg.payload) && msg.payload.length) return msg.payload[0];
return msg;
